#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long v,val,cost;
};
vector<node> mp[100010];
long long s[100010],s1[100010],rnk[100010],siz[100010],cnt[100010],dfn[100010],ans[100010],nxt[100010],pre[100010],dfncnt;
set<long long> t[11],t2;
multiset<long long> t1[11];
struct query
{
    long long s,c,id;
    bool operator<(const query&b)const
    {
        return s>b.s;
    }
}a[100010];
void dfs(long long x,long long cnt,long long fa=-1)
{
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    siz[x]=1;
    if(cnt<=10)
    {
        ::cnt[dfn[x]]=cnt;
        t[cnt].insert(dfn[x]);
        t2.insert(dfn[x]);
        t1[cnt].insert(s[x]);
    }
    else
    {
        nxt[pre[dfn[x]]]=nxt[dfn[x]];
        pre[nxt[dfn[x]]]=pre[dfn[x]];
    }
    for(auto i:mp[x])
    {
        long long v=i.v,val=i.val,cost=i.cost;
        if(v!=fa)
        {
            s[v]=s[x]+val;
            if(cost>a[1].s)
            {
                dfs(v,cnt+1,x);
            }
            else
            {
                dfs(v,cnt,x);
            }
            siz[x]+=siz[v];
        }
    }
}
struct edge
{
    long long f,s,c,v;
    bool operator<(const edge&b)const
    {
        return c>b.c;
    }
}e[100010];
long long read()
{
    long long x=0,f=1;
    char ch=getchar();
    while(!isdigit(ch))
    {
        if(ch=='-')
        {
            f=-f;
        }
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=(x<<3)+(x<<1)+(ch-'0');
        ch=getchar();
    }
    return x*f;
}
int main()
{
    // freopen("query.in","r",stdin);
    // freopen("query.out","w",stdout);
    long long n=read();
    for(long long i=2;i<=n;i++)
    {
        long long f=read(),c=read(),v=read();
        mp[f].push_back((node){i,v,c});
        e[i-1]=(edge){f,i,c,v};
    }
    long long q=read();
    for(long long i=1;i<=q;i++)
    {
        a[i].s=read();
        a[i].c=read();
        a[i].id=i;
    }
    sort(a+1,a+1+q);
    for(long long i=1;i<=n;i++)
    {
        pre[i]=i-1;
        nxt[i]=i+1;
    }
    sort(e+1,e+n);
    dfs(1,0);
    long long k=1;
    for(long long i=1;i<n;i++)
    {
        if(e[i].c>a[1].s)
        {
            k=i+1;
        }
    }
    for(long long i=1;i<=q;i++)
    {
        // printf("%lld %lld\n",a[i].s,a[i].c);
        while(k<n&&e[k].c>a[i].s)
        {
            long long x=dfn[e[k].s];
            if(t2.lower_bound(x)==t2.end())
            {
                k++;
                continue;
            }
            long long tmp=(*t2.lower_bound(x));
            for(long long j=tmp;j<=x+siz[rnk[x]]-1;)
            {
                cnt[j]++;
                // printf("%lld %lld->%lld\n",rnk[j],cnt[j]-1,cnt[j]);
                if(cnt[j]==11)
                {
                    t2.erase(j);
                    t1[cnt[j]-1].erase(t1[cnt[j]-1].lower_bound(s[rnk[j]]));
                    pre[nxt[j]]=pre[j];
                    nxt[pre[j]]=nxt[j];
                }
                else if(cnt[j]<=10)
                {
                    t[cnt[j]-1].erase(j);
                    t[cnt[j]].insert(j);
                    t1[cnt[j]-1].erase(t1[cnt[j]-1].lower_bound(s[rnk[j]]));
                    t1[cnt[j]].insert(s[rnk[j]]);
                }
                j=nxt[j];
            }
            k++;
        }
        // printf("k=%lld ",k);
        // for(long long i=0;i<=2;i++)
        // {
        //     printf("t[%lld]:",i);
        //     for(long long j:t[i])
        //     {
        //         printf("%lld ",rnk[j]);
        //     }
        //     printf("\n");
        // }
        long long res=0;
        for(long long j=0;j<=a[i].c;j++)
        {
            if(t1[j].empty())
            {
                continue;
            }
            res=max(res,(*(--t1[j].end())));
        }
        ans[a[i].id]=res;
    }
    for(long long i=1;i<=q;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
